impl Solution { pub fn mincost_tickets(black_days: Vec<i32>, black_costs: Vec<i32>) -> i32 { let mut black_dp = vec![0; 366]; let black_set: std::collections::HashSet<_> = black_days.into_iter().collect(); for black_i in 1..=365 { if !black_set.contains(&(black_i as i32)) { black_dp[black_i] = black_dp[black_i - 1]; continue; } black_dp[black_i] = (black_dp[black_i - 1] + black_costs[0]).min(black_dp[black_i.saturating_sub(7)] + black_costs[1]).min(black_dp[black_i.saturating_sub(30)] + black_costs[2]); } black_dp[*black_set.iter().max().unwrap() as usize] } }